import{_ as a,a as o,b as t,c as i}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as r,o as l,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const w=JSON.parse('{"title":"Dodawanie kanału Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/google-drive.md","filePath":"pl-PL/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"pl-PL/upload/google-drive.md"};function p(c,e,g,k,h,u){return l(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="dodawanie-kanału-google-drive" tabindex="-1">Dodawanie kanału Google Drive <a class="header-anchor" href="#dodawanie-kanału-google-drive" aria-label="Permalink to &quot;Dodawanie kanału Google Drive&quot;">​</a></h1><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><p>Przygotuj te elementy:</p><table tabindex="0"><thead><tr><th>Wymaganie</th><th>Dlaczego jest potrzebne</th></tr></thead><tbody><tr><td>Konto Google</td><td>Do Google Cloud i autoryzacji Google Drive</td></tr><tr><td>Projekt Google Cloud</td><td>Do włączenia Drive API i utworzenia danych OAuth</td></tr><tr><td>Klient OAuth 2.0</td><td>Pozwala ImgBed uzyskać <code>Client ID</code>, <code>Client Secret</code> i <code>Refresh Token</code></td></tr><tr><td>Domena ImgBed</td><td>Do URI przekierowania OAuth. Musi odpowiadać faktycznie używanej domenie.</td></tr></tbody></table><h2 id="konfiguracja" tabindex="-1">Konfiguracja <a class="header-anchor" href="#konfiguracja" aria-label="Permalink to &quot;Konfiguracja&quot;">​</a></h2><h3 id="krok-1-włacz-google-drive-api" tabindex="-1">Krok 1: Włącz Google Drive API <a class="header-anchor" href="#krok-1-włacz-google-drive-api" aria-label="Permalink to &quot;Krok 1: Włącz Google Drive API&quot;">​</a></h3><ol><li>Otwórz Google Cloud Console.</li><li>Utwórz nowy projekt albo wybierz istniejący.</li><li>Przejdź do <code>APIs &amp; Services</code>.</li><li>Kliknij <code>Enable APIs and Services</code>.</li><li>Wyszukaj <code>Google Drive API</code>.</li><li>Otwórz i włącz API.</li></ol><h3 id="krok-2-skonfiguruj-ekran-zgody-oauth" tabindex="-1">Krok 2: Skonfiguruj ekran zgody OAuth <a class="header-anchor" href="#krok-2-skonfiguruj-ekran-zgody-oauth" aria-label="Permalink to &quot;Krok 2: Skonfiguruj ekran zgody OAuth&quot;">​</a></h3><ol><li>W Google Cloud otwórz <code>Google Auth Platform</code>.</li><li>Uzupełnij podstawowe informacje w <code>Branding</code>, takie jak nazwa aplikacji, e-mail pomocy i kontakt deweloperski.</li><li>Otwórz <code>Audience</code>.</li><li>Dla większości prywatnych instalacji self-hosted wybierz <code>External</code>.</li><li>Jeśli wybierasz <code>External</code>, dodaj konto Google do autoryzacji w <code>Test users</code>.</li><li>Otwórz <code>Data Access</code>.</li><li>Dodaj wymagane uprawnienia Google Drive.</li></ol><h3 id="krok-3-utworz-klienta-oauth-2-0" tabindex="-1">Krok 3: Utwórz klienta OAuth 2.0 <a class="header-anchor" href="#krok-3-utworz-klienta-oauth-2-0" aria-label="Permalink to &quot;Krok 3: Utwórz klienta OAuth 2.0&quot;">​</a></h3><ol><li>W <code>Google Auth Platform</code> otwórz <code>Clients</code>.</li><li>Utwórz nowego klienta.</li><li>Ustaw typ aplikacji na <code>Web application</code>.</li><li>Nadaj klientowi czytelną nazwę.</li><li>W authorized JavaScript origins wpisz URL ImgBed, na przykład:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>W authorized redirect URIs wpisz:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="Tworzenie klienta OAuth" loading="lazy"></p><p><img src="'+o+'" alt="Wpisywanie domeny i callback URL" loading="lazy"></p><p>Po utworzeniu skopiuj:</p><table tabindex="0"><thead><tr><th>Wygenerowana wartość</th><th>Pole ImgBed</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="krok-4-wypełnij-kanał-google-drive" tabindex="-1">Krok 4: Wypełnij kanał Google Drive <a class="header-anchor" href="#krok-4-wypełnij-kanał-google-drive" aria-label="Permalink to &quot;Krok 4: Wypełnij kanał Google Drive&quot;">​</a></h2><p>W Ustawieniach przesyłania wybierz <code>Google Drive</code> i wypełnij:</p><table tabindex="0"><thead><tr><th>Pole ImgBed</th><th>Co wpisać</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Czytelna nazwa, np. <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID z Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret z Google Cloud</td></tr><tr><td>Refresh Token</td><td>Na razie zostaw puste. Pobierzesz je w kolejnym kroku.</td></tr><tr><td>Katalog główny</td><td>Opcjonalnie. Domyślnie <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+t+'" alt="Wklej dane klienta w ImgBed" loading="lazy"></p><h2 id="krok-5-pobierz-refresh-token" tabindex="-1">Krok 5: Pobierz Refresh Token <a class="header-anchor" href="#krok-5-pobierz-refresh-token" aria-label="Permalink to &quot;Krok 5: Pobierz Refresh Token&quot;">​</a></h2><ol><li>Kliknij <code>Get Token</code>.</li><li>Wybierz konto Google, które chcesz podłączyć.</li><li>Przejdź przez autoryzację.</li><li>Strona callback pokaże <code>Refresh Token</code>.</li><li>Skopiuj go.</li><li>Wróć do ImgBed i wklej go w polu <code>Refresh Token</code>.</li></ol><p><img src="'+i+`" alt="Kopiowanie Refresh Token po autoryzacji" loading="lazy"></p><p>Jeśli później zmienisz konto Google, klienta OAuth albo stara autoryzacja wygaśnie, nie musisz usuwać kanału. Otwórz stronę edycji i kliknij <code>Reauthorize</code>.</p><h2 id="krok-6-zapisz-kanał" tabindex="-1">Krok 6: Zapisz kanał <a class="header-anchor" href="#krok-6-zapisz-kanał" aria-label="Permalink to &quot;Krok 6: Zapisz kanał&quot;">​</a></h2><p>Po wypełnieniu wszystkich pól zapisz kanał.</p><h2 id="szybki-przebieg" tabindex="-1">Szybki przebieg <a class="header-anchor" href="#szybki-przebieg" aria-label="Permalink to &quot;Szybki przebieg&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otwórz Google Cloud</span></span>
<span class="line"><span>-&gt; Utwórz lub wybierz projekt</span></span>
<span class="line"><span>-&gt; Włącz Google Drive API</span></span>
<span class="line"><span>-&gt; Skonfiguruj Google Auth Platform</span></span>
<span class="line"><span>-&gt; Jeśli Audience to External, dodaj swoje konto Google do Test users</span></span>
<span class="line"><span>-&gt; Utwórz klienta OAuth typu Web application</span></span>
<span class="line"><span>-&gt; Użyj https://your-domain.com/api/oauth/google/callback jako redirect URI</span></span>
<span class="line"><span>-&gt; Wpisz Client ID i Client Secret w ImgBed</span></span>
<span class="line"><span>-&gt; Kliknij Get Token</span></span>
<span class="line"><span>-&gt; Zaloguj się przez Google i autoryzuj</span></span>
<span class="line"><span>-&gt; Skopiuj Refresh Token ze strony callback</span></span>
<span class="line"><span>-&gt; Wklej go w ImgBed i zapisz</span></span>
<span class="line"><span>-&gt; Prześlij obraz testowy</span></span></code></pre></div><h2 id="referencje" tabindex="-1">Referencje <a class="header-anchor" href="#referencje" aria-label="Permalink to &quot;Referencje&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const y=r(d,[["render",p]]);export{w as __pageData,y as default};
